import{_ as a,o as i,c as r,ag as t}from"./chunks/framework.B45ElpZ1.js";const p=JSON.parse('{"title":"tradecli wiki","description":"Documentation for the tradecli agent-native trading OS for Indian markets.","frontmatter":{"title":"tradecli wiki","description":"Documentation for the tradecli agent-native trading OS for Indian markets.","head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/"}]]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),o={name:"index.md"};function l(s,e,n,d,h,c){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="tradecli-wiki" tabindex="-1">tradecli wiki <a class="header-anchor" href="#tradecli-wiki" aria-label="Permalink to &quot;tradecli wiki&quot;">​</a></h1><p>Documentation for <code>tradecli</code> — the agent-native trading OS for Indian markets.</p><h2 id="what-is-tradecli" tabindex="-1">What is tradecli? <a class="header-anchor" href="#what-is-tradecli" aria-label="Permalink to &quot;What is tradecli?&quot;">​</a></h2><p><code>tradecli</code> is a local command layer for AI agents that operate across the tools Indian-market traders already use: MCP-backed broker tools, broker/browser screens, TradingView, Screener.in, portfolios, and a durable office memory layer.</p><p>The product shape is three parts:</p><ul><li><strong>tradecli OS</strong>: the local harness for tools, personas, broker sidecars, browser control, model runtime, and action policy.</li><li><strong>Agents</strong>: workers you spawn with a persona and mandate, from Learner and Investor to Trader, Hedge Fund, and PMS desks.</li><li><strong>AITradingOffice</strong>: the system of record for theses, forward tests, ledgers, reviews, employees, clients, and account context.</li></ul><p>Everything the agents do should remain visible and auditable from the operator&#39;s command surface. Broker credentials stay on your machine, and execution paths are gated behind explicit setup and review.</p><h2 id="office-mode" tabindex="-1">Office Mode <a class="header-anchor" href="#office-mode" aria-label="Permalink to &quot;Office Mode&quot;">​</a></h2><p>Office Mode lets one operator coordinate multiple specialist agents from the interactive TUI. Launch <code>tradecli</code>, choose Office Mode, and the mailbox coordinates delegation while AITradingOffice keeps the durable record behind the session.</p><h2 id="new-here" tabindex="-1">New here? <a class="header-anchor" href="#new-here" aria-label="Permalink to &quot;New here?&quot;">​</a></h2><p>Start with → <a href="/wiki/getting-started/quick-start">Quick Start</a></p><h2 id="explore-the-docs" tabindex="-1">Explore the docs <a class="header-anchor" href="#explore-the-docs" aria-label="Permalink to &quot;Explore the docs&quot;">​</a></h2><h3 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h3><h4 id="quick-start" tabindex="-1"><a href="/wiki/getting-started/quick-start">Quick Start</a> <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;[Quick Start](/getting-started/quick-start)&quot;">​</a></h4><ul><li>Install via Homebrew</li><li>Run first-time setup</li><li>Run <code>tradecli doctor</code></li><li>Launch the TUI</li><li>Pick your first workflow</li></ul><h4 id="broker-setup" tabindex="-1"><a href="/wiki/getting-started/broker-setup">Broker Setup</a> <a class="header-anchor" href="#broker-setup" aria-label="Permalink to &quot;[Broker Setup](/getting-started/broker-setup)&quot;">​</a></h4><ul><li>Run <code>tradecli setup</code></li><li>Groww first-use auth behavior</li><li>Zerodha Kite first-use login behavior</li><li>Local doctor repair path</li></ul><h4 id="browser-setup" tabindex="-1"><a href="/wiki/getting-started/browser-setup">Browser Setup</a> <a class="header-anchor" href="#browser-setup" aria-label="Permalink to &quot;[Browser Setup](/getting-started/browser-setup)&quot;">​</a></h4><ul><li>Why a dedicated browser</li><li>Chrome/Chromium requirements</li><li>The tradecli browser profile</li><li>First-run flow</li><li>Troubleshooting</li></ul><h4 id="llm-setup" tabindex="-1"><a href="/wiki/getting-started/llm-setup">LLM Setup</a> <a class="header-anchor" href="#llm-setup" aria-label="Permalink to &quot;[LLM Setup](/getting-started/llm-setup)&quot;">​</a></h4><ul><li>API-key providers</li><li>Subscription login paths</li><li>Auth storage</li><li>Verification</li></ul><h3 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to &quot;Guides&quot;">​</a></h3><h4 id="personas-modes" tabindex="-1"><a href="/wiki/guides/personas">Personas &amp; Modes</a> <a class="header-anchor" href="#personas-modes" aria-label="Permalink to &quot;[Personas &amp; Modes](/guides/personas)&quot;">​</a></h4><ul><li>Picking one</li><li>Switching</li><li>Office Mode</li></ul><h4 id="learner-mode" tabindex="-1"><a href="/wiki/guides/learner">Learner Mode</a> <a class="header-anchor" href="#learner-mode" aria-label="Permalink to &quot;[Learner Mode](/guides/learner)&quot;">​</a></h4><ul><li>How it works</li><li>Typical prompts</li><li>Switching away and back</li></ul><h4 id="investor" tabindex="-1"><a href="/wiki/guides/investor">Investor</a> <a class="header-anchor" href="#investor" aria-label="Permalink to &quot;[Investor](/guides/investor)&quot;">​</a></h4><ul><li>What it&#39;s for</li><li>Primary tools</li><li>Typical prompts</li></ul><h4 id="trader" tabindex="-1"><a href="/wiki/guides/trader">Trader</a> <a class="header-anchor" href="#trader" aria-label="Permalink to &quot;[Trader](/guides/trader)&quot;">​</a></h4><ul><li>What it&#39;s for</li><li>Primary tools</li><li>Typical prompts</li></ul><h4 id="pms-and-portfolio-workflows" tabindex="-1"><a href="/wiki/guides/portfolio-manager">PMS and Portfolio Workflows</a> <a class="header-anchor" href="#pms-and-portfolio-workflows" aria-label="Permalink to &quot;[PMS and Portfolio Workflows](/guides/portfolio-manager)&quot;">​</a></h4><ul><li>PMS mode in Office Mode</li><li>Portfolio context</li><li>Guardrails</li><li>Typical prompts</li></ul><h4 id="channels-api" tabindex="-1"><a href="/wiki/guides/channels-api">Channels &amp; API</a> <a class="header-anchor" href="#channels-api" aria-label="Permalink to &quot;[Channels &amp; API](/guides/channels-api)&quot;">​</a></h4><ul><li>What is a channel</li><li>The TUI channel</li><li>Telegram</li><li>WhatsApp</li><li>Gateway HTTP API</li></ul>',34)])])}const f=a(o,[["render",l]]);export{p as __pageData,f as default};
